import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './DataTable.css';

const DataTable = () => {
    const [data, setData] = useState([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [sortConfig, setSortConfig] = useState({ key: null, direction: 'asc' });
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);
    const [rowsPerPageOptions, setRowsPerPageOptions] = useState([10, 25, 50]);
    const [showModal, setShowModal] = useState(false);
    const [selectedRow, setSelectedRow] = useState(null);
  };

  useEffect(() => {
    fetchData();
  }, []);
  
  const fetchData = async () => {
    try {
      const response = await axios.get('https://jsonplaceholder.typicode.com/users');
      const fetchedData = response.data;
  
      // Repeat fetched data 10-15 times to get 100 rows
      let repeatedData = [];
      for (let i = 0; i < 10; i++) {
        repeatedData = repeatedData.concat(
          fetchedData.map((item) => ({
            ...item,
            id: item.id + i * fetchedData.length,
          }))
        );
      }
  
      setData(repeatedData);
    } catch (error) {
      console.error('Error fetching data:', error);
    }
  };

  const handleSearch = (event) => {
    setSearchTerm(event.target.value);
  };

  const handleRowsPerPageChange = (event) => {
    setItemsPerPage(parseInt(event.target.value, 10));
    setCurrentPage(1); // Reset current page to the first page
  };

  const handleSort = (key) => {
    let direction = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const handlePageClick = (newPage) => {
    setCurrentPage(newPage);
  };

  const handleEditClick = (rowData) => {
    setSelectedRow(rowData);
    setShowModal(true);
  };
  
  const handleModalClose = () => {
    setShowModal(false);
  };
  
  const handleSave = () => {
    // Update the data state with the edited row data
    setData((prevData) =>
      prevData.map((item) => (item.id === selectedRow.id ? selectedRow : item))
    );
  
    // Close the modal
    handleModalClose();
  
    // Send the updated data to the server (assuming an API endpoint exists)
    // axios.put(`https://yourapi.com/users/${selectedRow.id}`, selectedRow)
    // .then((response) => {
    //   console.log('Data saved:', response.data);
    // })
    // .catch((error) => {
    //   console.error('Error saving data:', error);
    // });
  };

  const filteredData = sortedData.filter((item) =>
    item.name.toLowerCase().includes(searchTerm.toLowerCase())
  );
const totalPages = Math.ceil(filteredData.length / itemsPerPage);
const startIndex = (currentPage - 1) * itemsPerPage;
const endIndex = startIndex + itemsPerPage;
const currentData = filteredData.slice(startIndex, endIndex);
